// famililook-shared/src/locale/useLocale.js
// Locale detection hook. Browser-only — no external API calls.
// Detection: AppStorage override > navigator.language > 'en-US' fallback.

import { useState, useCallback, useMemo } from 'react'

const STORAGE_KEY = 'fl:locale'

/**
 * @returns {{
 *   locale: string,
 *   language: string,
 *   country: string,
 *   source: 'override'|'browser'|'fallback',
 *   setLocale: (locale: string) => void,
 * }}
 */
export function useLocale() {
  const [localeOverride, setLocaleOverride] = useState(() => {
    try {
      if (typeof localStorage !== 'undefined') {
        return localStorage.getItem(STORAGE_KEY) || null
      }
    } catch { /* noop */ }
    return null
  })

  const detected = useMemo(() => {
    // Priority 1: AppStorage override
    if (localeOverride) {
      return { locale: localeOverride, source: 'override' }
    }

    // Priority 2: Browser locale
    if (typeof navigator !== 'undefined' && navigator.language) {
      return { locale: navigator.language, source: 'browser' }
    }

    // Priority 3: Fallback
    return { locale: 'en-US', source: 'fallback' }
  }, [localeOverride])

  const locale = detected.locale
  const parts = locale.split('-')
  const language = parts[0] || 'en'
  const country = parts[1] || ''

  const setLocale = useCallback((newLocale) => {
    try {
      if (typeof localStorage !== 'undefined') {
        localStorage.setItem(STORAGE_KEY, newLocale)
      }
    } catch { /* quota error */ }
    setLocaleOverride(newLocale)
  }, [])

  return {
    locale,
    language,
    country,
    source: detected.source,
    setLocale,
  }
}
