// famililook-shared/src/locale/currencyConfig.js
// Supported currencies and locale-to-currency detection.
// No API calls. Browser-only detection. USD is the global default.

export const CURRENCIES = {
  GBP: { code: 'GBP', symbol: '\u00a3', locale: 'en-GB', decimalPlaces: 2 },
  USD: { code: 'USD', symbol: '$', locale: 'en-US', decimalPlaces: 2 },
  EUR: { code: 'EUR', symbol: '\u20ac', locale: 'de-DE', decimalPlaces: 2 },
  CAD: { code: 'CAD', symbol: 'C$', locale: 'en-CA', decimalPlaces: 2 },
}

export const LOCALE_CURRENCY_MAP = {
  // GBP
  'en-GB': 'GBP',

  // USD (explicit + catch-all default for unsupported)
  'en-US': 'USD',
  'en-AU': 'USD',  // AUD not supported — fall back to USD

  // CAD
  'en-CA': 'CAD',

  // EUR — EU locale codes
  'de-DE': 'EUR', 'de-AT': 'EUR',
  'fr-FR': 'EUR', 'fr-BE': 'EUR',
  'es-ES': 'EUR', 'it-IT': 'EUR',
  'nl-NL': 'EUR', 'nl-BE': 'EUR',
  'pt-PT': 'EUR', 'el-GR': 'EUR',
  'fi-FI': 'EUR', 'ga-IE': 'EUR',
  'en-IE': 'EUR',
}

// USD for ALL unsupported locales — not GBP
export const DEFAULT_CURRENCY = 'USD'

// All supported currency codes for validation
export const SUPPORTED_CODES = Object.keys(CURRENCIES)
